Here's a modern MSTest approach for testing your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_WhenResponseIsSuccess()
    {
        var handler = new MockHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_WhenResponseIsError()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenTokenIsCanceled()
    {
        var handler = new MockHttpMessageHandler("ok", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(5));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // Fails test if it runs longer than 5s (guards against hangs)
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHttpMessageHandler("fast", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // Reusable test double — no mocking library needed
    private sealed class MockHttpMessageHandler(
        string content, HttpStatusCode statusCode, TimeSpan delay = default) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay > TimeSpan.Zero)
                await Task.Delay(delay, cancellationToken);

            return new HttpResponseMessage(statusCode)
            {
                Content = new StringContent(content)
            };
        }
    }
}
```

**Key modern MSTest patterns used:**

| Pattern | Detail |
|---------|--------|
| `async Task` test methods | MSTest natively awaits them — no `.Result` or `.GetAwaiter()` needed |
| `Assert.ThrowsExactlyAsync` | MSTest v3+ preferred over `ThrowsExceptionAsync` (exact type match, no subclass) |
| `[Timeout(ms)]` | Per-test hang protection; works with async tests in MSTest v3 |
| `CancellationToken` forwarding | Verifies your method actually honors the token |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over HTTP responses |

**Notes:**
- `[Timeout]` in MSTest v3 uses a cooperative `CancellationToken` via `TestContext.CancellationTokenSource` — it won't abort a thread, but will cancel async work.
- Use `Assert.ThrowsExactlyAsync` (MSTest v3.3+) over `ThrowsExceptionAsync` to avoid accidentally passing on derived exception types.
- If you need the test's built-in cancellation token (e.g., to respect `[Timeout]`), inject `TestContext` and use `TestContext.CancellationTokenSource.Token`.
